insert into bm_questions (level, topic, topic_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags) values
('t4', 1, 'Tatabahasa - Kata Adjektif', 'Pilih kata adjektif pancaindera yang sesuai untuk melengkapkan ayat ini: "Sup ayam yang dimasak oleh ibu berbau sangat __________."', 'mcq', array['A. hanyir', 'B. harum', 'C. kelat', 'D. tengik'], 'B', 'Kata adjektif ''harum'' menerangkan bau yang menyenangkan daripada makanan atau masakan.', 'easy', array['tatabahasa', 'kata_adjektif', 'pancaindera']),
('t4', 1, 'Tatabahasa - Kata Adjektif', 'Tayar kereta mainan yang baru dibeli oleh ayah itu berbentuk __________.', 'mcq', array['A. bulat', 'B. leper', 'C. bujur', 'D. segi tiga'], 'A', 'Tayar kenderaan berbentuk bulat untuk membolehkannya bergerak dengan lancar.', 'easy', array['tatabahasa', 'kata_adjektif', 'sifat_rupa']),
('t4', 1, 'Tatabahasa - Kata Adjektif', 'Antara ayat berikut, yang manakah menggunakan kata adjektif cara dengan betul?', 'mcq', array['A. Aliff memandu keretanya dengan lambat kerana tergesa-gesa.', 'B. Pelari itu berlari dengan pantas untuk memenangi perlumbaan.', 'C. Hujan turun dengan lebat di petang hari.', 'D. Murid itu menulis dengan kemas menggunakan pensel tajam.'], 'B', 'Kata adjektif cara ''pantas'' menerangkan cara pelari itu berlari dengan laju.', 'kbat', array['tatabahasa', 'kata_adjektif', 'cara']),
('t4', 1, 'Tatabahasa - Kata Adjektif', 'Perkataan ''merdu'' ialah kata adjektif pancaindera dengar yang menerangkan tentang bunyi suara atau muzik.', 'true_false', array['Betul', 'Salah'], 'Betul', 'Perkataan ''merdu'' merujuk kepada bunyi yang sedap didengar, seperti suara nyanyian atau gesekan biola.', 'easy', array['tatabahasa', 'kata_adjektif', 'pancaindera']),
('t4', 1, 'Tatabahasa - Kata Adjektif', 'Dalam ayat "Bilik tidur kakak sangat kemas dan bersih", perkataan ''kemas'' dan ''bersih'' merupakan kata adjektif ukuran.', 'true_false', array['Betul', 'Salah'], 'Salah', 'Perkataan ''kemas'' dan ''bersih'' merupakan kata adjektif keadaan, bukannya kata adjektif ukuran.', 'standard', array['tatabahasa', 'kata_adjektif', 'keadaan']),
('t4', 1, 'Tatabahasa - Kata Adjektif', 'Air laut di kawasan Selat Melaka itu kelihatan __________ biru apabila cuaca cerah. (Isi tempat kosong dengan kata penguat yang sesuai)', 'fill_blank', null, 'sangat', 'Kata penguat ''sangat'', ''amat'', atau ''sungguh'' digunakan sebelum kata adjektif warna ''biru'' untuk menunjukkan darjah warna tersebut.', 'easy', array['tatabahasa', 'kata_adjektif', 'kata_penguat']),
('t4', 1, 'Tatabahasa - Kata Adjektif', 'Lengkapkan ayat berikut dengan kata adjektif waktu yang sesuai: "Kita mestilah bangun __________ pagi supaya tidak terlewat ke sekolah."', 'fill_blank', null, 'awal', 'Kata adjektif ''awal'' menunjukkan waktu yang mendahului waktu yang ditetapkan.', 'standard', array['tatabahasa', 'kata_adjektif', 'waktu']);
insert into bm_questions (level, topic, topic_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags) values
('t4', 2, 'Tatabahasa - Imbuhan', 'Pilih perkataan yang menggunakan imbuhan awalan dengan betul untuk melengkapkan ayat: "Ahmad sedang __________ buku cerita di perpustakaan."', 'mcq', array['A. dibaca', 'B. membaca', 'C. pembaca', 'D. terbaca'], 'B', 'Imbuhan awalan ''meN-'' (membaca) menunjukkan kata kerja aktif transitif yang sesuai dengan perbuatan Ahmad membaca buku.', 'easy', array['tatabahasa', 'imbuhan', 'awalan']),
('t4', 2, 'Tatabahasa - Imbuhan', '"Seni pertahanan diri itu __________ oleh guru silat yang berpengalaman."', 'mcq', array['A. diajarkan', 'B. belajar', 'C. mengajar', 'D. pelajaran'], 'A', 'Perkataan ''diajarkan'' menggunakan imbuhan apitan ''di-...-kan'' untuk membina ayat pasif yang sesuai dengan konteks ayat.', 'standard', array['tatabahasa', 'imbuhan', 'apitan']),
('t4', 2, 'Tatabahasa - Imbuhan', 'Kenal pasti perkataan berimbuhan apitan dalam ayat ini yang menunjukkan proses atau hasil daripada sesuatu tindakan: "Persatuan Ibu Bapa dan Guru mengadakan perbincangan tentang keselamatan murid."', 'mcq', array['A. keselamatan', 'B. perbincangan', 'C. mengadakan', 'D. persatuan'], 'B', 'Kata nama ''perbincangan'' (daripada kata dasar bincang) bermaksud proses atau hal berbincang.', 'kbat', array['tatabahasa', 'imbuhan', 'apitan', 'kata_nama']),
('t4', 2, 'Tatabahasa - Imbuhan', 'Apakah imbuhan akhiran yang sesuai untuk menukarkan kata dasar ''lukis'' menjadi kata nama yang bermaksud gambar yang dilukis?', 'mcq', array['A. -an (lukisan)', 'B. -kan (lukiskan)', 'C. -i (lukisi)', 'D. -wan (lukiswan)'], 'A', 'Imbuhan akhiran ''-an'' pada kata dasar ''lukis'' menghasilkan kata nama ''lukisan'' yang merujuk kepada hasil seni lukis.', 'easy', array['tatabahasa', 'imbuhan', 'akhiran']),
('t4', 2, 'Tatabahasa - Imbuhan', 'Pilih penggunaan imbuhan apitan yang betul bagi kata dasar ''besar'' untuk mengisi tempat kosong dalam ayat.', 'mcq', array['A. memperbesarkan', 'B. membesarkan', 'C. diperbesarkan', 'D. memperbesar-besarkan'], 'B', 'Kata kerja ''membesarkan'' adalah betul. Kata ''memperbesar'' juga betul tetapi tidak boleh diikuti dengan akhiran ''-kan'' (penggunaan ''memperbesarkan'' adalah salah dari segi tatabahasa).', 'standard', array['tatabahasa', 'imbuhan', 'apitan', 'kesalahan_lazim']),
('t4', 2, 'Tatabahasa - Imbuhan', '"Buku-buku di atas meja itu berselerak." Apakah maksud imbuhan awalan ''ber-'' pada perkataan ''berselerak''?', 'mcq', array['A. mempunyai sesuatu', 'B. dalam keadaan terbiar atau bertaburan', 'C. melakukan perbuatan sendiri', 'D. saling berkaitan antara satu sama lain'], 'B', 'Imbuhan awalan ''ber-'' pada perkataan ''berselerak'' menunjukkan keadaan bertaburan atau bersepah.', 'kbat', array['tatabahasa', 'imbuhan', 'awalan']),
('t4', 2, 'Tatabahasa - Imbuhan', 'Tulis kata berimbuhan yang betul bagi kata dasar ''tulis'' untuk melengkapkan ayat pasif berikut: "Surat kiriman itu __________ oleh abang kelmarin."', 'fill_blank', null, 'ditulis', 'Imbuhan awalan ''di-'' digunakan untuk membentuk kata kerja pasif ''ditulis'' bagi menunjukkan perbuatan yang dilakukan oleh orang ketiga (abang).', 'standard', array['tatabahasa', 'imbuhan', 'awalan', 'kata_kerja_pasif']);
insert into bm_questions (level, topic, topic_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags) values
('t4', 3, 'Tatabahasa - Ayat Tunggal dan Majmuk', 'Antara berikut, yang manakah merupakan contoh ayat tunggal?', 'mcq', array['A. Bapa membaca surat khabar manakala ibu memasak di dapur.', 'B. Aminah menyanyi dengan merdu sekali.', 'C. Haziq tidak pergi ke padang kerana hujan lebat.', 'D. Murid-murid sedang belajar dan guru sedang memerhati.'], 'B', 'Ayat tunggal hanya mengandungi satu subjek (''Aminah'') dan satu predikat (''menyanyi dengan merdu sekali'').', 'easy', array['tatabahasa', 'ayat_tunggal']),
('t4', 3, 'Tatabahasa - Ayat Tunggal dan Majmuk', 'Pilih kata hubung yang paling sesuai untuk menggabungkan dua ayat tunggal berikut: \nAyat 1: "Siti suka melukis." \nAyat 2: "Siti tidak suka mewarna."', 'mcq', array['A. dan', 'B. tetapi', 'C. lalu', 'D. sambil'], 'B', 'Kata hubung pertentangan ''tetapi'' digunakan untuk menunjukkan dua perkara yang bertentangan sifatnya.', 'standard', array['tatabahasa', 'ayat_majmuk', 'kata_hubung']),
('t4', 3, 'Tatabahasa - Ayat Tunggal dan Majmuk', 'Fahami ayat majmuk ini: "Aiman menyanyi sambil memetik gitar di atas pentas." Apakah dua ayat tunggal yang membentuk ayat majmuk di atas?', 'mcq', array['A. Aiman menyanyi. Gitar dipetik di atas pentas.', 'B. Aiman menyanyi di atas pentas. Aiman memetik gitar di atas pentas.', 'C. Aiman menyanyi. Aiman bermain gitar.', 'D. Aiman menyanyi lagu. Aiman membeli gitar.'], 'B', 'Ayat majmuk gabungan tersebut dibentuk daripada dua ayat tunggal yang berkongsi subjek (''Aiman'') dan keterangan tempat (''di atas pentas'').', 'kbat', array['tatabahasa', 'ayat_majmuk', 'analisis_ayat']),
('t4', 3, 'Tatabahasa - Ayat Tunggal dan Majmuk', 'Apakah jenis ayat bagi ayat berikut: "Adik menangis kerana kakinya terluka."', 'mcq', array['A. Ayat tunggal', 'B. Ayat tanya', 'C. Ayat majmuk', 'D. Ayat seruan'], 'C', 'Ayat ini merupakan ayat majmuk kerana terdiri daripada dua klausa yang digabungkan menggunakan kata hubung pancangan ''kerana''.', 'easy', array['tatabahasa', 'ayat_majmuk']),
('t4', 3, 'Tatabahasa - Ayat Tunggal dan Majmuk', 'Ayat majmuk boleh dibentuk dengan menggabungkan tiga atau lebih ayat tunggal menggunakan kata hubung yang sesuai.', 'true_false', array['Betul', 'Salah'], 'Betul', 'Ayat majmuk boleh terdiri daripada gabungan beberapa ayat tunggal dengan menggunakan satu atau lebih kata hubung untuk menyambungkannya.', 'standard', array['tatabahasa', 'ayat_majmuk']),
('t4', 3, 'Tatabahasa - Ayat Tunggal dan Majmuk', 'Gabungkan dua ayat tunggal berikut menggunakan kata hubung yang sesuai: "Fatimah rajin belajar." "Fatimah mendapat keputusan yang cemerlang."', 'fill_blank', null, 'sehingga', 'Kata hubung ''sehingga'' digunakan untuk menerangkan akibat atau kesan daripada sikap Fatimah yang rajin belajar.', 'easy', array['tatabahasa', 'ayat_majmuk', 'kata_hubung']);
insert into bm_questions (level, topic, topic_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags) values
('t4', 4, 'Karangan - Membina Perenggan dan Menyusun Ayat', 'Pilih susunan ayat yang betul untuk membentuk satu perenggan pendahuluan karangan bertajuk "Faedah Membaca Buku": \n(I) Buku ialah jambatan ilmu. \n(II) Oleh itu, kita mestilah rajin membaca pada setiap hari. \n(III) Membaca buku memberikan banyak pengetahuan kepada kita.', 'mcq', array['A. I, II, III', 'B. I, III, II', 'C. III, I, II', 'D. II, I, III'], 'B', 'Susunan bermula dengan penyataan umum (I), diikuti dengan penjelasan (III), dan kesimpulan kecil atau cadangan (II).', 'easy', array['karangan', 'menyusun_ayat', 'perenggan_pendahuluan']),
('t4', 4, 'Karangan - Membina Perenggan dan Menyusun Ayat', 'Apakah penanda wacana yang sesuai digunakan untuk memulakan perenggan isi yang kedua dalam sebuah karangan?', 'mcq', array['A. Pada pendapat saya', 'B. Selain itu', 'C. Akhir sekali', 'D. Pada masa yang sama'], 'B', 'Penanda wacana ''Selain itu'' sangat sesuai digunakan untuk menambah isi baharu dalam perenggan seterusnya.', 'standard', array['karangan', 'penanda_wacana', 'membina_perenggan']),
('t4', 4, 'Karangan - Membina Perenggan dan Menyusun Ayat', '"Sukan dapat menyihatkan tubuh badan kita. Apabila kita bersukan, badan kita akan berpeluh. Peluh yang keluar ini akan menyingkirkan toksin dalam badan." Apakah isi utama bagi perenggan di atas?', 'mcq', array['A. Peluh menyingkirkan toksin dari badan.', 'B. Sukan dapat menyihatkan tubuh badan.', 'C. Kita perlu bersukan pada setiap petang.', 'D. Badan manusia menghasilkan peluh yang banyak.'], 'B', 'Ayat pertama ialah ayat topik yang menyatakan idea utama iaitu sukan dapat menyihatkan tubuh badan, manakala ayat seterusnya ialah huraian.', 'kbat', array['karangan', 'idea_utama', 'pemahaman_perenggan']),
('t4', 4, 'Karangan - Membina Perenggan dan Menyusun Ayat', 'Susun ayat-ayat di bawah supaya menjadi sebuah cerita yang logik tentang berkelah di pantai. \n(P) Kami menolong ibu menghidangkan makanan di atas tikar. \n(Q) Selepas kenyang, kami bermain pasir di tepi pantai. \n(R) Sebaik sahaja tiba di pantai, kami mencari tempat yang redup.', 'mcq', array['A. P, Q, R', 'B. R, P, Q', 'C. R, Q, P', 'D. Q, R, P'], 'B', 'Urutan aktiviti bermula dengan mencari tempat (R), diikuti dengan makan (P), dan kemudian bermain (Q).', 'easy', array['karangan', 'menyusun_ayat', 'penceritaan']),
('t4', 4, 'Karangan - Membina Perenggan dan Menyusun Ayat', 'Pilih ayat tanya yang paling sesuai untuk mendapatkan maklumat bagi menulis karangan autobiografi "Aku Sebatang Pensel".', 'mcq', array['A. Di manakah aku dilahirkan?', 'B. Bagaimanakah cara untuk menggunakan pensel?', 'C. Mengapakah murid-murid suka menulis?', 'D. Berapakah harga pensel di kedai buku?'], 'A', 'Karangan autobiografi menceritakan latar belakang diri (asal-usul benda), jadi pertanyaan "Di manakah aku dilahirkan?" membantu memulakan perenggan pendahuluan.', 'standard', array['karangan', 'autobiografi', 'membina_ayat']),
('t4', 4, 'Karangan - Membina Perenggan dan Menyusun Ayat', 'Semasa menulis perenggan penutup karangan jenis syarahan, apakah perkara utama yang perlu dimasukkan oleh seorang penulis?', 'mcq', array['A. Mengucapkan terima kasih dan memohon maaf sebelum mengundur diri.', 'B. Memperkenalkan tajuk syarahan kepada penonton.', 'C. Memberikan huraian panjang tentang kebaikan bersukan.', 'D. Menulis pantun jenaka untuk menghiburkan hakim.'], 'A', 'Perenggan penutup syarahan wajib diakhiri dengan permohonan maaf atas sebarang kesilapan dan ucapan terima kasih kepada penonton.', 'standard', array['karangan', 'format_karangan', 'syarahan']),
('t4', 4, 'Karangan - Membina Perenggan dan Menyusun Ayat', '"Hari Ahad yang lalu, kami sekeluarga bergotong-royong membersihkan rumah. Ayah mengecat dinding luar. Ibu menyapu sampah. Saya pula __________." Pilih huraian perbuatan yang paling sesuai untuk melengkapkan draf isi karangan tersebut.', 'mcq', array['A. menonton televisyen di ruang tamu', 'B. menyiram pokok bunga di halaman rumah', 'C. pergi bermain basikal bersama kawan', 'D. tidur dengan lena di dalam bilik'], 'B', 'Menyiram pokok bunga ialah tugas pembersihan/pengemasan rumah yang sesuai dengan aktiviti gotong-royong keluarga, manakala pilihan lain bukan tugas gotong-royong.', 'kbat', array['karangan', 'membina_perenggan', 'logik_cerita']),
('t4', 4, 'Karangan - Membina Perenggan dan Menyusun Ayat', 'Sebuah karangan yang baik untuk murid Tahun 4 perlu mempunyai sekurang-kurangnya tiga bahagian utama iaitu pendahuluan, isi-isi penting, and penutup.', 'true_false', array['Betul', 'Salah'], 'Betul', 'Struktur karangan standard bahasa Melayu sekolah rendah terdiri daripada tiga komponen wajib iaitu pendahuluan, perenggan isi, dan penutup.', 'easy', array['karangan', 'struktur_karangan']),
('t4', 4, 'Karangan - Membina Perenggan dan Menyusun Ayat', 'Ayat topik ialah ayat yang berfungsi untuk menghuraikan secara terperinci contoh-contoh bagi isi perenggan.', 'true_false', array['Betul', 'Salah'], 'Salah', 'Ayat topik ialah ayat yang menyatakan idea atau tema utama perenggan tersebut. Ayat yang menghuraikan contoh ialah ayat contoh atau ayat huraian.', 'standard', array['karangan', 'membina_perenggan', 'struktur_perenggan']),
('t4', 4, 'Karangan - Membina Perenggan dan Menyusun Ayat', 'Susun perkataan-perkataan berikut untuk membentuk ayat yang gramatis: "sekolah / murid-murid / membersihkan / kawasan / bergotong-royong / untuk"', 'fill_blank', null, 'Murid-murid bergotong-royong untuk membersihkan kawasan sekolah.', 'Struktur ayat penyata aktif transitif bermula dengan subjek (Murid-murid) diikuti kata kerja (bergotong-royong) dan penerangan tujuan (untuk membersihkan kawasan sekolah).', 'easy', array['karangan', 'membina_ayat', 'menyusun_perkataan']);
insert into bm_questions (level, topic, topic_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags) values
('t4', 5, 'Karangan - Format Karangan dan Penulisan Kreatif', 'Apakah format yang wajib ada pada bahagian permulaan sebuah karangan laporan?', 'mcq', array['A. Alamat pengirim dan penerima', 'B. Tajuk laporan dengan huruf besar pada setiap awal kata', 'C. Tarikh hari ini di sebelah kanan surat', 'D. Tandatangan penulis di bahagian atas laporan'], 'B', 'Karangan laporan memerlukan tajuk laporan yang jelas ditulis di bahagian atas/tengah halaman.', 'easy', array['karangan', 'format_karangan', 'laporan']),
('t4', 5, 'Karangan - Format Karangan dan Penulisan Kreatif', 'Dalam menulis surat kiriman rasmi, bagaimanakah cara penulisan tarikh yang betul mengikut format tatabahasa bahasa Melayu?', 'mcq', array['A. 21/06/2026', 'B. 21 JUN 2026', 'C. 21 Jun 2026.', 'D. 21 Jun 2026'], 'D', 'Format tarikh surat rasmi ditulis dengan nama bulan bermula huruf besar dan tiada tanda noktah di hujungnya (contoh: 21 Jun 2026).', 'standard', array['karangan', 'format_karangan', 'surat_rasmi']),
('t4', 5, 'Karangan - Format Karangan dan Penulisan Kreatif', 'Anda ingin menulis karangan tentang cara-cara membalas jasa ibu bapa. Antara isi berikut, yang manakah paling utama dan bertepatan dengan peranan seorang anak yang masih bersekolah?', 'mcq', array['A. Membelikan ibu bapa sebuah kereta mewah yang baharu.', 'B. Belajar bersungguh-sungguh dan menghormati mereka pada setiap masa.', 'C. Memberikan wang belanja bulanan yang banyak hasil daripada bekerja sambilan.', 'D. Membawa mereka melancong ke luar negara setiap bulan.'], 'B', 'Bagi murid Tahun 4 (kanak-kanak sekolah), tanggungjawab utama yang praktikal untuk membalas jasa ibu bapa ialah belajar dengan tekun dan menjaga adab sopan.', 'kbat', array['karangan', 'huraian_isi', 'KBAT']),
('t4', 5, 'Karangan - Format Karangan dan Penulisan Kreatif', 'Apakah kata sapaan atau panggilan hormat yang sesuai digunakan untuk menulis surat kiriman tidak rasmi kepada seorang sahabat?', 'mcq', array['A. Menghadap Yang Berhormat Tan Sri', 'B. Ke hadapan sahabatku yang berada di Kuala Lumpur', 'C. Tuan Guru Besar yang dihormati', 'D. Rujukan tuan bertarikh semalam'], 'B', 'Surat kiriman tidak rasmi kepada rakan menggunakan kata sapaan mesra seperti ''Ke hadapan sahabatku''.', 'easy', array['karangan', 'format_karangan', 'surat_tidak_rasmi']),
('t4', 5, 'Karangan - Format Karangan dan Penulisan Kreatif', 'Pilihlah penutup yang paling sesuai untuk karangan catatan harian perkhemahan pengakap sekolah.', 'mcq', array['A. Kami bersurai setelah penat bermain di pusat membeli-belah berhampiran.', 'B. Kami pulang ke rumah dengan gembira walaupun berasa letih kerana mendapat banyak pengalaman berharga.', 'C. Sila pastikan khemah dilipat dengan kemas sebelum anda pulang.', 'D. Pada waktu petang, kami mandi-manda di sungai dengan gembiranya.'], 'B', 'Penutup catatan perkhemahan yang baik menceritakan perasaan gembira/letih semasa pulang dan nilai/pengalaman yang diperoleh.', 'standard', array['karangan', 'catatan_harian', 'penutup_karangan']),
('t4', 5, 'Karangan - Format Karangan dan Penulisan Kreatif', 'Karangan jenis berita mestilah bermula dengan nama tempat ditulis dengan huruf besar sepenuhnya, diikuti dengan tanda koma dan tarikh sebelum perenggan pertama bermula.', 'true_false', array['Betul', 'Salah'], 'Betul', 'Format penulisan berita bahasa Melayu memerlukan pengepala kepala berita seperti "KUALA LUMPUR, 21 Jun -" di awal perenggan pertama.', 'easy', array['karangan', 'format_karangan', 'berita']),
('t4', 5, 'Karangan - Format Karangan dan Penulisan Kreatif', 'Antara berikut, yang manakah merupakan peraturan penting semasa menulis surat kiriman tidak rasmi untuk peperiksaan sekolah?', 'mcq', array['A. Boleh menggunakan singkatan ejaan seperti ''yg'' dan ''dgn''', 'B. Mesti menggunakan bahasa Melayu baku dan ejaan yang penuh', 'C. Boleh menggunakan bahasa rojak agar kelihatan mesra', 'D. Tiada had dan format khusus yang perlu dipatuhi'], 'B', 'Walaupun surat tidak rasmi bersifat santai, ejaan penuh dan bahasa baku tetap diwajibkan dalam penulisan karangan formal sekolah.', 'standard', array['karangan', 'surat_tidak_rasmi', 'tatabahasa']),
('t4', 5, 'Karangan - Format Karangan dan Penulisan Kreatif', 'Dalam karangan jenis dialog, nama watak yang bercakap mestilah ditulis di sebelah kiri, diikuti oleh tanda baca __________ sebelum kata-kata watak tersebut ditulis.', 'fill_blank', null, 'titik bertindih', 'Tanda baca titik bertindih (:) digunakan selepas nama watak dalam format penulisan dialog.', 'standard', array['karangan', 'format_karangan', 'dialog', 'tanda_baca']),
('t4', 5, 'Karangan - Format Karangan dan Penulisan Kreatif', 'Karangan yang menceritakan pengalaman sendiri menyertai rombongan ke Melaka Bandaraya Bersejarah tergolong dalam jenis karangan __________.', 'fill_blank', null, 'keperihalan', 'Karangan keperihalan atau gambaran ialah karangan yang menceritakan peristiwa, lawatan, atau pengalaman sebenar yang dialami.', 'easy', array['karangan', 'jenis_karangan', 'keperihalan']),
('t4', 5, 'Karangan - Format Karangan dan Penulisan Kreatif', 'Apabila menulis karangan cerita tentang membantu mangsa banjir, kita boleh memasukkan nilai murni seperti "bantu-membantu" dan "keprihatinan" untuk menjadikan cerita tersebut lebih menarik dan bermoral.', 'true_false', array['Betul', 'Salah'], 'Betul', 'Memasukkan nilai-nilai murni dan teladan yang baik dapat meningkatkan mutu pengajaran dalam karangan naratif.', 'kbat', array['karangan', 'naratif', 'nilai_murni']);
insert into bm_questions (level, topic, topic_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags) values
('f3', 1, 'Tatabahasa', 'Pilih ayat pasif yang betul bagi ayat aktif: "Saya telah membaca buku sejarah itu semalam."', 'mcq', array['Buku sejarah itu telah dibaca oleh saya semalam.', 'Buku sejarah itu telah saya baca semalam.', 'Buku sejarah itu saya telah membaca semalam.', 'Buku sejarah itu telah dibaca semalam oleh saya.'], 'Buku sejarah itu telah saya baca semalam.', 'Bagi kata ganti nama diri pertama (saya, aku, kami, kita), bentuk pasif tidak boleh menggunakan kata kerja berimbuhan ''di-'' dan sendi nama ''oleh''. Kata ganti nama diri pertama mesti mendahului kata kerja dasar yang telah digugurkan imbuhan aktifnya.', 'standard', array['tatabahasa', 'sintaksis']),
('f3', 1, 'Tatabahasa', 'Pilih ayat pasif yang betul bagi ayat aktif: "Kamu mesti menyiapkan tugasan itu sebelum hari esok."', 'mcq', array['Tugasan itu mesti disiapkan oleh kamu sebelum hari esok.', 'Tugasan itu mesti kamu siapkan sebelum hari esok.', 'Tugasan itu kamu mesti siapkan sebelum hari esok.', 'Tugasan itu disiapkan oleh kamu mesti sebelum hari esok.'], 'Tugasan itu mesti kamu siapkan sebelum hari esok.', 'Bagi kata ganti nama diri kedua (kamu, anda, awak), ayat pasif dibentuk dengan meletakkan kata ganti nama diri kedua sebelum kata kerja dasar tanpa imbuhan ''di-'' dan ''oleh''.', 'standard', array['tatabahasa', 'sintaksis']),
('f3', 1, 'Tatabahasa', 'Pilih ayat pasif yang betul bagi ayat aktif: "Encik Ali memandu kereta baharu itu ke pejabat."', 'mcq', array['Kereta baharu itu dipandu oleh Encik Ali ke pejabat.', 'Kereta baharu itu Encik Ali pandu ke pejabat.', 'Kereta baharu itu dipandu ke pejabat oleh beliau.', 'Kereta baharu itu memandu oleh Encik Ali ke pejabat.'], 'Kereta baharu itu dipandu oleh Encik Ali ke pejabat.', 'Bagi kata ganti nama diri ketiga (dia, mereka, beliau) atau nama khas/am (Encik Ali), ayat pasif dibentuk dengan kata kerja berawalan ''di-'' dan diikuti oleh kata sendi ''oleh''.', 'easy', array['tatabahasa', 'sintaksis']),
('f3', 1, 'Tatabahasa', 'Kenal pasti ayat pasif yang salah tatabahasanya.', 'mcq', array['Surat kiriman rasmi itu telah kami hantar kepada pihak penganjur.', 'Segala nasihat ibu akan saya ingat sampai bila-bila.', 'Kuih-muih yang lazat itu telah dihidangkan oleh kami kepada para tetamu.', 'Tugasan yang rumit itu dapat diselesaikan oleh mereka dalam masa sejam.'], 'Kuih-muih yang lazat itu telah dihidangkan oleh kami kepada para tetamu.', 'Ayat ini salah kerana menggunakan formula ''dihidangkan oleh kami'' (kata ganti nama diri pertama pasif menggunakan di- dan oleh). Sepatutnya ialah ''Kuih-muih yang lazat itu telah kami hidangkan kepada para tetamu.''', 'kbat', array['tatabahasa', 'sintaksis']),
('f3', 1, 'Tatabahasa', 'Pilih cakap pindah yang betul bagi cakap ajuk berikut:
insert into bm_questions (level, topic, topic_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags) values
('f3', 2, 'Karangan', 'Berapakah jumlah patah perkataan yang ditetapkan bagi penulisan Karangan Pendek (Bahagian A) dalam peperiksaan UASA Kertas 2?', 'mcq', array['30 hingga 50 patah perkataan.', '50 hingga 80 patah perkataan.', '80 hingga 120 patah perkataan.', 'Tidak kurang daripada 180 patah perkataan.'], '50 hingga 80 patah perkataan.', 'Mengikut format rasmi UASA Kertas 2 Bahagian A, murid dikehendaki menulis karangan pendek yang panjangnya antara 50 hingga 80 patah perkataan.', 'easy', array['karangan_pendek']),
('f3', 2, 'Karangan', 'Apakah aspek yang paling penting ketika menulis Karangan Pendek berdasarkan bahan grafik?', 'mcq', array['Menulis huraian yang sangat panjang sehingga melebihi 150 perkataan.', 'Memasukkan semua kata kunci atau frasa rangsangan yang diberikan dalam soalan.', 'Menggunakan format surat kiriman rasmi.', 'Mengabaikan gambar dan hanya menulis idea sendiri.'], 'Memasukkan semua kata kunci atau frasa rangsangan yang diberikan dalam soalan.', 'Calon wajib menyepadukan semua frasa atau kata kunci rangsangan yang disediakan ke dalam perenggan karangan pendek untuk mendapat markah penuh bagi aspek isi.', 'standard', array['karangan_pendek']),
('f3', 2, 'Karangan', 'Mengikut Formula Karangan 5 Perenggan (Blueprint Karangan), bagaimanakah pembahagian perenggan yang paling seimbang?', 'mcq', array['1 perenggan pendahuluan, 3 perenggan isi, 1 perenggan penutup.', '1 perenggan pendahuluan, 2 perenggan isi, 2 perenggan penutup.', '2 perenggan pendahuluan, 2 perenggan isi, 1 perenggan penutup.', '5 perenggan yang semuanya mengandungi isi tanpa pendahuluan dan penutup.'], '1 perenggan pendahuluan, 3 perenggan isi, 1 perenggan penutup.', 'Formula Karangan 5 Perenggan membahagikan karangan secara sistematik kepada 1 perenggan pendahuluan, 3 perenggan isi utama, dan 1 perenggan penutup.', 'easy', array['wacana']),
('f3', 2, 'Karangan', 'Dalam "Formula Mudah 6 Ayat" untuk membina perenggan isi, apakah fungsi bagi Ayat 1 (Pendapat)?', 'mcq', array['Menyatakan contoh konkrit bagi isi.', 'Menyatakan pendirian awal atau tajuk kecil perenggan isi tersebut.', 'Menerangkan impak atau kesan jangka panjang isi.', 'Merumuskan keseluruhan isi perenggan.'], 'Menyatakan pendirian awal atau tajuk kecil perenggan isi tersebut.', 'Ayat 1 (Pendapat - P) berfungsi sebagai ayat topik yang memperkenalkan isi atau cadangan utama yang akan dibincangkan dalam perenggan tersebut.', 'standard', array['wacana']),
('f3', 2, 'Karangan', 'Manakah antara penanda wacana berikut yang paling sesuai digunakan untuk memulakan Ayat 3 (Huraian - H) dalam perenggan isi?', 'mcq', array['Sebagai tamsilnya,...', 'Hal ini dikatakan demikian kerana...', 'Impaknya,...', 'Oleh itu, jelaslah bahawa...'], 'Hal ini dikatakan demikian kerana...', 'Penanda wacana ''Hal ini dikatakan demikian kerana...'' digunakan untuk memberikan penjelasan mendalam atau huraian sebab dan akibat bagi menyokong isi.', 'easy', array['wacana']),
('f3', 2, 'Karangan', 'Apakah peranan utama Ayat 4 (Isi & Contoh - IC) dalam struktur penulisan perenggan isi karangan?', 'mcq', array['Mengulang semula isi utama untuk kali ketiga.', 'Mengemukakan bukti konkrit atau contoh realistik bagi menyokong hujah.', 'Memberikan cadangan baharu yang berbeza daripada isi utama.', 'Menyimpulkan keseluruhan karangan.'], 'Mengemukakan bukti konkrit atau contoh realistik bagi menyokong hujah.', 'Ayat 4 (IC) bertujuan memperkukuh hujah dengan membekalkan contoh konkrit yang sahih, praktikal, dan mudah difahami pembaca.', 'standard', array['wacana']),
('f3', 2, 'Karangan', 'Pilih ayat yang paling tepat menggambarkan "Kesan (K)" dalam perenggan isi bertemakan Langkah Mengurangkan Pencemaran Sungai.', 'mcq', array['Kesannya, kualiti air sungai akan meningkat dan ekosistem hidupan akuatik akan terpelihara.', 'Kerajaan perlulah mendenda kilang-kilang yang membuang sisa toksik ke dalam sungai.', 'Sebagai contoh, kempen Cintai Sungai Kita boleh dilaksanakan di seluruh negara.', 'Hal ini dikatakan demikian kerana sampah-sarap menyumbat aliran air sungai.'], 'Kesannya, kualiti air sungai akan meningkat dan ekosistem hidupan akuatik akan terpelihara.', 'Ayat ini menunjukkan kesan langsung (implikasi positif) daripada tindakan yang dicadangkan dalam isi perenggan.', 'standard', array['wacana']),
('f3', 2, 'Karangan', 'Susun semula ayat-ayat di bawah mengikut urutan "Formula Mudah 6 Ayat" (P, I, H, IC, K, PH) yang betul bagi menghasilkan perenggan isi yang koheren.
